// 1. Safely grab the Vendor ID
let vendorId = null;
try {
  vendorId = $('Check Vendor Exists2').first().json.vendor.id;
} catch(e) {
  vendorId = null;
}

// 2. Safely grab the Message ID
let gmailId = null;
try {
  gmailId = $('Merge Email + PDF Data2').first().json.gmailMessageId;
} catch(e) {
  try {
    gmailId = $('Microsoft Outlook Trigger2').first().json.id || null;
  } catch(e2) {
    gmailId = null;
  }
}

// 3. Parse the output from the AI node
const raw = $input.first().json.output ?? '';
const clean = raw
  .replace(/```json\n?/g, '')
  .replace(/```\n?/g, '')
  .trim();

let extracted;
try {
  extracted = JSON.parse(clean);
} catch(e) {
  extracted = {
    invoice_number: null,
    amount: null,
    taxable_amount: null,
    billing_period_start: null,
    billing_period_end: null,
    line_items: [],
    anomaly_flags: ['JSON parse failed — manual review required']
  };
}

// 4. Calculate amount from line items if Claude didn't find it
const lineItems = extracted.line_items ?? [];
const calculatedAmount = lineItems.reduce((sum, item) => sum + (Number(item.total) || 0), 0);

const amount = extracted.amount ?? extracted.total_amount ?? (calculatedAmount > 0 ? calculatedAmount : 0);
const taxableAmount = extracted.taxable_amount ?? extracted.amount ?? (calculatedAmount > 0 ? calculatedAmount : 0);

// 5. Return the fully prepped JSON
return [{
  json: {
    vendor_id: vendorId,
    invoice_number: extracted.invoice_number,
    amount: amount,
    taxable_amount: taxableAmount,
    cgst_amount: extracted.cgst_amount ?? 0,
    sgst_amount: extracted.sgst_amount ?? 0,
    igst_amount: extracted.igst_amount ?? 0,
    billing_period_start: extracted.billing_period_start,
    billing_period_end: extracted.billing_period_end,
    line_items: JSON.parse(JSON.stringify(lineItems)),
    anomaly_flags: JSON.parse(JSON.stringify(extracted.anomaly_flags ?? [])),
    status: 'PENDING_L1',
    gmail_message_id: gmailId
  }
}];

const response = $input.all();

let vendorFound = false;
let vendor = null;

if (response.length > 0 && response[0].json && response[0].json.id) {
  vendorFound = true;
  vendor = response[0].json;
}

// Use .first() instead of .item to avoid "Multiple matches" error
const emailData = $('Microsoft Outlook Trigger2').first().json;

const senderEmail =
  emailData.from?.emailAddress?.address ||
  emailData.sender?.emailAddress?.address ||
  '';

const senderName =
  emailData.from?.emailAddress?.name ||
  emailData.sender?.emailAddress?.name ||
  '';

const subject = emailData.subject || '(no subject)';

const emailReceivedAt =
  emailData.receivedDateTime ||
  emailData.date ||
  new Date().toISOString();

const messageId =
  emailData.id ||
  emailData.internetMessageId ||
  '';

// Use .first() here too
const pdfData = $('Extract PDF Text2').first().json;
const pdfText = pdfData.text || '';
const pdfPages = pdfData.numpages || 0;

return [{
  json: {
    vendorFound,
    vendor,
    senderEmail,
    senderName,
    subject,
    emailReceivedAt,
    messageId,
    pdfText,
    pdfPages,
  },
}];

const body = JSON.stringify({
  model: "claude-sonnet-4-6",
  max_tokens: 10,
  stream: false,
  system: "You are a document classifier. Reply with ONE word only: CONTRACT, BILL, or OTHER.",
  messages: [
    {
      role: "user",
      content: "Email subject: " + ($json.subject || "") + "\n\nDocument text:\n" + ($json.pdfText || "").substring(0, 2000) + "\n\nONE word only:"
    }
  ]
});

return [{ json: { ...$json, claudeBody: body } }];

