const originalEmail = $('Extract Email Metadata3').first();

return [{
  json: originalEmail.json,
  binary: originalEmail.binary
}];

function generateToken() {
  let token = '';
  const chars = '0123456789abcdef';
  for (let i = 0; i < 64; i++) token += chars[Math.floor(Math.random() * 16)];
  return token;
}

// Supabase returns the inserted row(s). With "return=representation" the body
// is an ARRAY ([{...}]). Unwrap it so we always get the real UUID.
const resp = $('Supabase — Insert Bill5').first().json;
const billRow = Array.isArray(resp) ? (resp[0] || {}) : resp;
const billId = billRow.id || null;

if (!billId) {
  throw new Error('No bill id returned from Insert Bill — cannot create approval tokens');
}

const approveToken = generateToken();
const rejectToken  = generateToken();
const baseUrl = 'https://mirragiohimanshu.app.n8n.cloud/webhook/approval';

return [{
  json: {
    bill_id:      billId,
    approveToken: approveToken,
    rejectToken:  rejectToken,
    approveLink:  baseUrl + '?token=' + approveToken,
    rejectLink:   baseUrl + '?token=' + rejectToken
  }
}];

try {
  const allInputs = $input.all();

  let isDuplicate = false;
  let existingBillId = null;

  // Check both duplicate check results
  for (const input of allInputs) {
    const result = input.json;
    // Supabase returns array — if it has items, it's a duplicate
    if (Array.isArray(result) && result.length > 0) {
      isDuplicate = true;
      existingBillId = result[0].id;
      break;
    }
  }

  // ✅ Get bill data directly from Prepare Bill for Insert
  const billData = $('Prepare Bill for Insert2').first().json;

  return [{
    json: {
      ...billData,
      isDuplicate,
      existingBillId
    }
  }];

} catch(err) {
  return [{
    json: {
      isDuplicate: false,
      existingBillId: null,
      error: err.message
    }
  }];
}

// Scan EVERY incoming email item and emit ONE output item per PDF attachment.
// Handles a single email with many PDFs AND multiple emails arriving in one poll.
const out = [];
for (const inItem of $input.all()) {
  const binary = inItem.binary || {};
  const binaryKeys = Object.keys(binary);
  const pdfKeys = binaryKeys.filter((key) => {
    const b = binary[key];
    return b.mimeType === 'application/pdf'
      || b.fileName?.toLowerCase().endsWith('.pdf')
      || (b.mimeType === 'application/octet-stream' && b.fileName?.toLowerCase().endsWith('.pdf'));
  });

  if (pdfKeys.length === 0) {
    out.push({
      json: { ...inItem.json, pdfAttachmentKey: null, pdfFileName: null, noPdfFound: true,
              allAttachmentKeys: binaryKeys, totalAttachments: binaryKeys.length, totalPdfs: 0 },
      binary: inItem.binary
    });
    continue;
  }

  pdfKeys.forEach((pdfKey, idx) => {
    out.push({
      json: { ...inItem.json, pdfAttachmentKey: pdfKey, pdfFileName: binary[pdfKey].fileName,
              pdfIndex: idx, noPdfFound: false, allAttachmentKeys: binaryKeys,
              totalAttachments: binaryKeys.length, totalPdfs: pdfKeys.length },
      binary: inItem.binary
    });
  });
}
return out;

// Get the PDF text from Extract PDF Text
const pdfData = $input.first().json;

// Get the email metadata from before the PDF extraction
const emailData = $('Loop PDFs').item.json;

return [{
  json: {
    // Email metadata
    senderEmail: emailData.senderEmail,
    senderName: emailData.senderName,
    subject: emailData.subject,
    emailReceivedAt: emailData.emailReceivedAt,
    gmailMessageId: emailData.gmailMessageId,
    hasAttachment: emailData.hasAttachment,
    pdfAttachmentKey: emailData.pdfAttachmentKey,

    // PDF content
    pdfText: pdfData.text || '',
    pdfPages: pdfData.numpages || 0
  },
  binary: $input.first().binary
}];

// Re-attach original PDF binary for Supabase Storage upload.
// We reference the binary from 'Code in JavaScript1' which identified the PDF key.
const billData = $input.first().json;
const billArr  = Array.isArray(billData) ? billData : [billData];
const bill     = billArr[0] || {};
const billId   = bill.id   || null;
const invoiceNo = bill.invoice_number || null;

const origBinary = $('Loop PDFs').item.binary || {};
const pdfKey     = $('Loop PDFs').item.json.pdfAttachmentKey || null;

const safeName   = (invoiceNo || billId || 'bill').toString().replace(/[^a-zA-Z0-9_\-]/g, '_');
const storagePath = 'Invoice_' + safeName + '.pdf';

return [{
  json: { bill_id: billId, invoice_number: invoiceNo, storagePath },
  binary: (pdfKey && origBinary[pdfKey]) ? { pdfData: origBinary[pdfKey] } : {}
}];

// Build public URL from the storage path; handle upload failure gracefully.
const storagePath  = $('Prepare PDF Upload2').first().json.storagePath;
const billId       = $('Prepare PDF Upload2').first().json.bill_id;
const uploadResult = $input.first().json || {};

// Supabase Storage returns { Key: 'bills/...' } on success
const uploadOk = !!(uploadResult.Key || uploadResult.path || uploadResult.Id);
const pdfUrl   = uploadOk
  ? 'https://ydoitzgqavfmbyrirxxe.supabase.co/storage/v1/object/public/bills/' + storagePath
  : null;

return [{ json: { bill_id: billId, bill_pdf_url: pdfUrl } }];
